<!-- 功能说明
管理员查看客户详情，包含客户基本信息、历史订单、咨询记录，支持添加备注（防抖保存），核心对接客户详情、订单列表、咨询列表、备注接口。 -->

<template>
  <view class="customer-detail-container">
    <!-- 页面头部 -->
    <view class="page-header">
      <button class="back-btn" @click="navigateBack">
        <image src="/static/images/back.png" class="back-icon"></image>
      </button>
      <text class="header-title">客户详情</text>
    </view>

    <!-- 客户基本信息区域 -->
    <view class="info-section">
      <view class="info-header">
        <image :src="customerInfo.avatar || '/static/images/default-avatar.png'" class="avatar-img"></image>
        <view class="info-main">
          <text class="nickname">{{customerInfo.nickname || '未设置昵称'}}</text>
          <text class="user-type" :class="customerInfo.userType === 'ENTERPRISE' ? 'type-enterprise' : 'type-personal'">
            {{customerInfo.userType === 'ENTERPRISE' ? '企业用户' : '个人用户'}}
          </text>
        </view>
      </view>
      <view class="info-detail">
        <view class="detail-item">
          <text class="detail-label">手机号：</text>
          <text class="detail-value">{{customerInfo.phone || '未绑定'}}</text>
        </view>
        <view class="detail-item">
          <text class="detail-label">首次登录：</text>
          <text class="detail-value">{{formatTime(customerInfo.firstLoginTime) || '未知'}}</text>
        </view>
        <view class="detail-item">
          <text class="detail-label">最近登录：</text>
          <text class="detail-value">{{formatTime(customerInfo.lastLoginTime) || '未知'}}</text>
        </view>
        <view class="detail-item" v-if="customerInfo.userType === 'ENTERPRISE'">
          <text class="detail-label">企业名称：</text>
          <text class="detail-value">{{customerInfo.enterpriseName || '未认证'}}</text>
        </view>
        <view class="detail-item" v-if="customerInfo.userType === 'ENTERPRISE'">
          <text class="detail-label">认证状态：</text>
          <text class="detail-value" :class="customerInfo.isEnterpriseAuth ? 'auth-success' : 'auth-pending'">
            {{customerInfo.isEnterpriseAuth ? '已认证' : '未认证'}}
          </text>
        </view>
      </view>
    </view>

    <!-- 客户备注区域 -->
    <view class="remark-section">
      <text class="section-title">客户备注</text>
      <textarea 
        class="remark-input" 
        v-model="customerRemark" 
        placeholder="可添加客户备注信息（自动保存）"
        maxlength="500"
        @input="saveRemark"
      ></textarea>
      <text class="saving-hint" v-if="isSaving">保存中...</text>
    </view>

    <!-- 历史订单区域 -->
    <view class="order-section">
      <text class="section-title">历史订单（{{orderList.length}}）</text>
      <view class="order-list" v-if="orderList.length > 0">
        <view class="order-item" v-for="(item, index) in orderList" :key="item.orderNo" @click="goToOrderDetail(item.orderNo)">
          <view class="order-header">
            <text class="order-no">订单号：{{item.orderNo}}</text>
            <text class="order-status" :class="getStatusClass(item.status)">{{getStatusText(item.status)}}</text>
          </view>
          <view class="order-body">
            <text class="order-time">下单时间：{{formatTime(item.createTime)}}</text>
            <text class="order-amount">订单金额：¥{{item.totalAmount.toFixed(2)}}</text>
            <text class="order-goods">商品数量：{{item.goodsCount}}件</text>
          </view>
        </view>
      </view>
      <view class="empty-order" v-else>
        <image src="/static/images/empty-order.png" class="empty-img"></image>
        <text class="empty-text">该客户暂无订单记录</text>
      </view>
    </view>

    <!-- 咨询记录区域 -->
    <view class="consult-section">
      <text class="section-title">咨询记录（{{consultList.length}}）</text>
      <view class="consult-list" v-if="consultList.length > 0">
        <view class="consult-item" v-for="(item, index) in consultList" :key="item.id">
          <view class="consult-header">
            <text class="consult-time">{{formatTime(item.createTime)}}</text>
            <text class="consult-status" :class="item.status === 'HANDLED' ? 'status-handled' : 'status-unhandled'">
              {{item.status === 'HANDLED' ? '已处理' : '未处理'}}
            </text>
          </view>
          <view class="consult-content">
            <text class="content-label">客户咨询：</text>
            <text class="content-text">{{item.content}}</text>
          </view>
          <view class="reply-content" v-if="item.replyContent">
            <text class="reply-label">客服回复：</text>
            <text class="reply-text">{{item.replyContent}}</text>
          </view>
        </view>
      </view>
      <view class="empty-consult" v-else>
        <image src="/static/images/empty-consult.png" class="empty-img"></image>
        <text class="empty-text">该客户暂无咨询记录</text>
      </view>
    </view>
  </view>
</template>

<script setup>
import { ref } from 'vue';
import { onLoad, onUnload } from '@dcloudio/uni-app';
import { useUserStore } from '@/store/modules/userStore';
import request from '@/utils/request';

// 状态管理
const userStore = useUserStore();

// 页面数据
const customerId = ref(''); // 客户ID
const customerInfo = ref({
  id: '',
  nickname: '',
  avatar: '',
  phone: '',
  userType: 'PERSONAL',
  firstLoginTime: '',
  lastLoginTime: '',
  enterpriseName: '',
  isEnterpriseAuth: false,
  remark: ''
});
const customerRemark = ref(''); // 客户备注
const orderList = ref([]); // 客户历史订单
const consultList = ref([]); // 客户咨询记录
const isSaving = ref(false); // 备注保存状态
let remarkTimer = null; // 备注防抖定时器

// 页面加载获取客户详情数据
onLoad((options) => {
  if (!userStore.token || !['ADMIN', 'CUSTOMER_SERVICE'].includes(userStore.userInfo.role)) {
    uni.navigateTo({ url: '/pages/admin/login' });
    return;
  }
  
  // 从options获取路由参数
  customerId.value = options.customerId || '';
  
  if (!customerId.value) {
    uni.showToast({ title: '客户ID不能为空', icon: 'none' });
    setTimeout(() => {
      uni.navigateBack();
    }, 1500);
    return;
  }
  
  getCustomerDetail();
  getCustomerOrders();
  getCustomerConsult();
});

// 页面卸载清除定时器
onUnload(() => {
  if (remarkTimer) clearTimeout(remarkTimer);
});

// 接口请求：获取客户详情
const getCustomerDetail = async () => {
  uni.showLoading({ title: '加载中' });
  try {
    const res = await request({
      url: '/api/admin/customer/detail',
      method: 'GET',
      params: { id: customerId.value }
    });
    if (res.success) {
      customerInfo.value = res.data;
      customerRemark.value = res.data.remark || '';
    }
  } catch (error) {
    uni.showToast({ title: '客户信息加载失败', icon: 'none' });
  } finally {
    uni.hideLoading();
  }
};

// 接口请求：获取客户历史订单
const getCustomerOrders = async () => {
  try {
    const res = await request({
      url: '/api/admin/customer/orders',
      method: 'GET',
      params: { id: customerId.value, pageNum: 1, pageSize: 20 }
    });
    if (res.success) {
      orderList.value = res.data.list || [];
    }
  } catch (error) {
    uni.showToast({ title: '订单记录加载失败', icon: 'none' });
  }
};

// 接口请求：获取客户咨询记录
const getCustomerConsult = async () => {
  try {
    const res = await request({
      url: '/api/admin/customer/consult',
      method: 'GET',
      params: { id: customerId.value, pageNum: 1, pageSize: 20 }
    });
    if (res.success) {
      consultList.value = res.data.list || [];
    }
  } catch (error) {
    uni.showToast({ title: '咨询记录加载失败', icon: 'none' });
  }
};

// 保存客户备注（防抖处理）
const saveRemark = () => {
  if (isSaving.value) return;
  const remark = customerRemark.value.trim();
  // 与原备注一致则无需保存
  if (remark === customerInfo.value.remark) return;

  clearTimeout(remarkTimer);
  remarkTimer = setTimeout(async () => {
    isSaving.value = true;
    try {
      const res = await request({
        url: '/api/admin/customer/remark',
        method: 'POST',
        data: { id: customerId.value, remark }
      });
      if (res.success) {
        uni.showToast({ title: '备注保存成功' });
        customerInfo.value.remark = remark;
      } else {
        uni.showToast({ title: '备注保存失败', icon: 'none' });
      }
    } catch (error) {
      uni.showToast({ title: '网络异常，保存失败', icon: 'none' });
    } finally {
      isSaving.value = false;
    }
  }, 500);
};

// 格式化时间
const formatTime = (time) => {
  if (!time) return '';
  const date = new Date(time);
  return `${date.getFullYear()}-${(date.getMonth() + 1).toString().padStart(2, '0')}-${date.getDate().toString().padStart(2, '0')} ${date.getHours().toString().padStart(2, '0')}:${date.getMinutes().toString().padStart(2, '0')}`;
};

// 根据订单状态获取显示文本
const getStatusText = (status) => {
  const statusMap = {
    'PENDING_PAYMENT': '待支付',
    'PENDING_CONFIRM': '待确认',
    'PENDING_SHIPMENT': '待发货',
    'PENDING_RECEIPT': '待收货',
    'COMPLETED': '已完成',
    'CANCELLED': '已取消',
    'AFTER_SALE': '售后中'
  };
  return statusMap[status] || '未知状态';
};

// 根据订单状态获取样式类
const getStatusClass = (status) => {
  const classMap = {
    'PENDING_PAYMENT': 'status-pending',
    'PENDING_CONFIRM': 'status-confirm',
    'PENDING_SHIPMENT': 'status-ship',
    'PENDING_RECEIPT': 'status-receipt',
    'COMPLETED': 'status-complete',
    'CANCELLED': 'status-cancel',
    'AFTER_SALE': 'status-aftersale'
  };
  return classMap[status] || '';
};

// 跳转订单详情页
const goToOrderDetail = (orderNo) => {
  uni.navigateTo({ url: `/pages/admin/order/detail?orderNo=${orderNo}` });
};

// 返回上一页
const navigateBack = () => {
  uni.navigateBack();
};
</script>

